import React from "react";

const PlayerList = ({ players, updateCurrentPlayer }) => {
  return (
    <div>
      {players.length === 0 ? (
        <p>No Players</p> // Display this message when the players array is empty
      ) : (
        <ul>
          {players.map((player) => (
            <li key={player.id} onClick={() => updateCurrentPlayer(player)}>
              {player.name}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default PlayerList;
